mapper.select:
SELECT l.*, ar.approver_name as lastApproverName, ar.comment_text as lastApproverOpinion FROM oa_leave l LEFT JOIN ( SELECT business_key, approver_name, comment_text FROM oa_approval_record WHERE action_type = 'approve' ORDER BY create_time DESC ) ar ON CONCAT('leave:', l.leave_id) = ar.business_key WHERE l.approval_status IN ('approved', 'rejected')
AND l.dept_id = #{deptId}
ORDER BY l.create_time DESC LIMIT #{limit}
